import{_ as e,c as a,o as i,a1 as t}from"./chunks/framework.DILC4Csi.js";const k=JSON.parse('{"title":"Superpowers 集成: 配置工作流 | opencode-agent-skills","description":"学习 Superpowers 模式的安装和配置方法。通过环境变量启用工作流指导，掌握工具映射和命名空间优先级规则。","frontmatter":{"title":"Superpowers 集成: 配置工作流 | opencode-agent-skills","subtitle":"Superpowers 集成: 配置工作流 | opencode-agent-skills","sidebarTitle":"启用 Superpowers","description":"学习 Superpowers 模式的安装和配置方法。通过环境变量启用工作流指导，掌握工具映射和命名空间优先级规则。","tags":["进阶配置","工作流","Superpowers"],"prerequisite":["start-installation"],"order":2},"headers":[],"relativePath":"zh/joshuadavidthomas/opencode-agent-skills/advanced/superpowers-integration/index.md","filePath":"zh/joshuadavidthomas/opencode-agent-skills/advanced/superpowers-integration/index.md"}'),l={name:"zh/joshuadavidthomas/opencode-agent-skills/advanced/superpowers-integration/index.md"};function n(p,s,o,r,d,h){return i(),a("div",null,[...s[0]||(s[0]=[t('<h1 id="superpowers-工作流集成" tabindex="-1">Superpowers 工作流集成 <a class="header-anchor" href="#superpowers-工作流集成" aria-label="Permalink to &quot;Superpowers 工作流集成&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>了解 Superpowers 工作流的价值和适用场景</li><li>正确安装和配置 Superpowers 模式</li><li>理解工具映射和技能命名空间系统</li><li>掌握压缩恢复时 Superpowers 的自动注入机制</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>你可能在考虑这些问题：</p><ul><li><strong>工作流不够规范</strong>：团队成员的开发习惯不统一，代码质量参差不齐</li><li><strong>缺少严格流程</strong>：虽然有技能库，但 AI 助手没有明确的流程指导</li><li><strong>工具调用混乱</strong>：Superpowers 定义的工具与 OpenCode 的原生工具名称不同，导致调用失败</li><li><strong>迁移成本高</strong>：已经在使用 Superpowers，担心切换到 OpenCode 后需要重新配置</li></ul><p>这些问题都会影响开发效率和代码质量。</p><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">什么是 Superpowers？</p><p>Superpowers 是一个完整的软件开发工作流框架，通过组合式技能提供严格的工作流程指导。它定义了规范的开发步骤、工具调用方式和命名空间系统。</p></div><p><strong>OpenCode Agent Skills 提供了无缝的 Superpowers 集成</strong>，通过环境变量启用后，会自动注入完整的工作流指导，包括：</p><ol><li><strong>using-superpowers 技能内容</strong>：Superpowers 核心工作流指令</li><li><strong>工具映射</strong>：将 Superpowers 定义的工具名映射到 OpenCode 原生工具</li><li><strong>技能命名空间</strong>：明确技能的优先级和引用方式</li></ol><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><p>在开始之前，请确保：</p><div class="warning custom-block"><p class="custom-block-title">前置检查</p><ul><li>✅ 已安装 <a href="./../../start/installation/">opencode-agent-skills 插件</a></li><li>✅ 熟悉基本的技能发现机制</li></ul></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-安装-superpowers" tabindex="-1">第 1 步：安装 Superpowers <a class="header-anchor" href="#第-1-步-安装-superpowers" aria-label="Permalink to &quot;第 1 步：安装 Superpowers&quot;">​</a></h3><p><strong>为什么</strong> 需要先安装 Superpowers 项目，本插件才能发现 <code>using-superpowers</code> 技能。</p><p><strong>操作方式</strong></p><p>根据你的需求，选择以下任一方式安装 Superpowers：</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-JzMVu" id="tab-xL1lzzG" checked><label data-title="作为 Claude Code 插件" for="tab-xL1lzzG">作为 Claude Code 插件</label><input type="radio" name="group-JzMVu" id="tab-smPJaed"><label data-title="作为 OpenCode 技能" for="tab-smPJaed">作为 OpenCode 技能</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">//</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 按照</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Superpowers</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 官方文档安装</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">//</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/obra/superpowers</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">//</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 技能会自动位于</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.claude/plugins/...</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">//</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 手动安装为</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> OpenCode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 技能</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/opencode/skills</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/obra/superpowers</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/opencode/skills/superpowers</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">//</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 技能会位于</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .opencode/skills/superpowers/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (项目级) 或 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/.config/opencode/skills/superpowers/ (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">用户级</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></div></div><p><strong>你应该看到</strong>：</p><ul><li>安装后，Superpowers 的技能目录包含 <code>using-superpowers/SKILL.md</code> 文件</li></ul><h3 id="第-2-步-启用-superpowers-模式" tabindex="-1">第 2 步：启用 Superpowers 模式 <a class="header-anchor" href="#第-2-步-启用-superpowers-模式" aria-label="Permalink to &quot;第 2 步：启用 Superpowers 模式&quot;">​</a></h3><p><strong>为什么</strong> 通过环境变量告诉插件启用 Superpowers 模式，插件会在会话初始化时自动注入相关内容。</p><p><strong>操作方式</strong></p><p>临时启用（仅当前终端会话）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">true</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opencode</span></span></code></pre></div><p>永久启用（添加到 Shell 配置文件）：</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-TF9eh" id="tab-_5684ld" checked><label data-title="Bash (~/.bashrc 或 ~/.bash_profile)" for="tab-_5684ld">Bash (~/.bashrc 或 ~/.bash_profile)</label><input type="radio" name="group-TF9eh" id="tab-I22rznz"><label data-title="Zsh (~/.zshrc)" for="tab-I22rznz">Zsh (~/.zshrc)</label><input type="radio" name="group-TF9eh" id="tab-F4IZleM"><label data-title="PowerShell (~/.config/powershell/Microsoft.PowerShell_profile.ps1)" for="tab-F4IZleM">PowerShell (~/.config/powershell/Microsoft.PowerShell_profile.ps1)</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;export OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE=true&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.bashrc</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.bashrc</span></span></code></pre></div><div class="language-zsh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">zsh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;export OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE=true&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.zshrc</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.zshrc</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">System.Environment</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]::SetEnvironmentVariable(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;true&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;User&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></div></div><p><strong>你应该看到</strong>：</p><ul><li>输入 <code>echo $OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE</code> 显示 <code>true</code></li></ul><h3 id="第-3-步-验证自动注入" tabindex="-1">第 3 步：验证自动注入 <a class="header-anchor" href="#第-3-步-验证自动注入" aria-label="Permalink to &quot;第 3 步：验证自动注入&quot;">​</a></h3><p><strong>为什么</strong> 确认插件正确识别 Superpowers 技能，并在新会话开始时自动注入内容。</p><p><strong>操作方式</strong></p><ol><li>重启 OpenCode</li><li>创建一个新会话</li><li>在新会话中输入任何消息（如 &quot;你好&quot;）</li><li>查看会话上下文（如果 OpenCode 支持）</li></ol><p><strong>你应该看到</strong>：</p><ul><li>插件在后台自动注入了以下内容（格式化为 XML）：</li></ul><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">EXTREMELY_IMPORTANT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">You have superpowers.</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">**IMPORTANT: The using-superpowers skill content is included below. It is ALREADY LOADED - do not call use_skill for it again. Use use_skill only for OTHER skills.**</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[using-superpowers 技能的实际内容...]</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">**Tool Mapping for OpenCode:**</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">- `TodoWrite` → `todowrite`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">- `Task` tool with subagents → Use `task` tool with `subagent_type`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">- `Skill` tool → `use_skill`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">- `Read`, `Write`, `Edit`, `Bash`, `Glob`, `Grep`, `WebFetch` → Use native lowercase OpenCode tools</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">**Skill namespace priority:**</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">1. Project: `project:skill-name`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">2. Claude project: `claude-project:skill-name`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">3. User: `skill-name`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">4. Claude user: `claude-user:skill-name`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">5. Marketplace: `claude-plugins:skill-name`</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">The first discovered match wins.</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">EXTREMELY_IMPORTANT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><p>完成上述步骤后，验证以下内容：</p><table tabindex="0"><thead><tr><th>检查项</th><th>预期结果</th></tr></thead><tbody><tr><td>环境变量设置正确</td><td><code>echo $OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE</code> 输出 <code>true</code></td></tr><tr><td>Superpowers 技能可发现</td><td>调用 <code>get_available_skills()</code> 能看到 <code>using-superpowers</code></td></tr><tr><td>新会话自动注入</td><td>创建新会话后，AI 知道自己有 superpowers</td></tr></tbody></table><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="❌-错误-1-技能未被发现" tabindex="-1">❌ 错误 1：技能未被发现 <a class="header-anchor" href="#❌-错误-1-技能未被发现" aria-label="Permalink to &quot;❌ 错误 1：技能未被发现&quot;">​</a></h3><p><strong>现象</strong>：启用了环境变量，但插件没有注入 Superpowers 内容。</p><p><strong>原因</strong>：Superpowers 安装位置不在技能发现路径中。</p><p><strong>解决方案</strong>：</p><ul><li>确认 Superpowers 安装在以下任一位置： <ul><li><code>.claude/plugins/...</code> （Claude Code 插件缓存）</li><li><code>.opencode/skills/...</code> （OpenCode 技能目录）</li><li><code>~/.config/opencode/skills/...</code> （OpenCode 用户技能）</li><li><code>~/.claude/skills/...</code> （Claude 用户技能）</li></ul></li><li>运行 <code>get_available_skills()</code> 验证 <code>using-superpowers</code> 是否在列表中</li></ul><h3 id="❌-错误-2-工具调用失败" tabindex="-1">❌ 错误 2：工具调用失败 <a class="header-anchor" href="#❌-错误-2-工具调用失败" aria-label="Permalink to &quot;❌ 错误 2：工具调用失败&quot;">​</a></h3><p><strong>现象</strong>：AI 尝试调用 <code>TodoWrite</code> 或 <code>Skill</code> 工具，提示工具不存在。</p><p><strong>原因</strong>：AI 没有应用工具映射，仍在使用 Superpowers 定义的名称。</p><p><strong>解决方案</strong>：</p><ul><li>插件会自动注入工具映射，确保 <code>&lt;EXTREMELY_IMPORTANT&gt;</code> 标签被正确注入</li><li>如果问题持续，检查会话是否在启用环境变量后创建</li></ul><h3 id="❌-错误-3-压缩后-superpowers-消失" tabindex="-1">❌ 错误 3：压缩后 Superpowers 消失 <a class="header-anchor" href="#❌-错误-3-压缩后-superpowers-消失" aria-label="Permalink to &quot;❌ 错误 3：压缩后 Superpowers 消失&quot;">​</a></h3><p><strong>现象</strong>：长时间会话后，AI 不再遵循 Superpowers 工作流。</p><p><strong>原因</strong>：上下文压缩导致之前的注入内容被清理。</p><p><strong>解决方案</strong>：</p><ul><li>插件会在 <code>session.compacted</code> 事件后自动重新注入 Superpowers 内容</li><li>如果问题持续，检查插件是否正常监听事件</li></ul><h2 id="工具映射详解" tabindex="-1">工具映射详解 <a class="header-anchor" href="#工具映射详解" aria-label="Permalink to &quot;工具映射详解&quot;">​</a></h2><p>插件会自动注入以下工具映射，帮助 AI 正确调用 OpenCode 工具：</p><table tabindex="0"><thead><tr><th>Superpowers 工具</th><th>OpenCode 工具</th><th>说明</th></tr></thead><tbody><tr><td><code>TodoWrite</code></td><td><code>todowrite</code></td><td>Todo 写入工具</td></tr><tr><td><code>Task</code> (带 subagents)</td><td><code>task</code> + <code>subagent_type</code></td><td>子代理调用</td></tr><tr><td><code>Skill</code></td><td><code>use_skill</code></td><td>加载技能</td></tr><tr><td><code>Read</code> / <code>Write</code> / <code>Edit</code></td><td>原生小写工具</td><td>文件操作</td></tr><tr><td><code>Bash</code> / <code>Glob</code> / <code>Grep</code> / <code>WebFetch</code></td><td>原生小写工具</td><td>系统操作</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">为什么需要工具映射？</p><p>Superpowers 原生设计基于 Claude Code，工具名称与 OpenCode 不一致。通过自动映射，AI 可以无缝使用 OpenCode 的原生工具，无需手动转换。</p></div><h2 id="技能命名空间优先级" tabindex="-1">技能命名空间优先级 <a class="header-anchor" href="#技能命名空间优先级" aria-label="Permalink to &quot;技能命名空间优先级&quot;">​</a></h2><p>当多个来源存在同名技能时，插件按以下优先级选择：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. project:skill-name         (项目级 OpenCode 技能)</span></span>\n<span class="line"><span>2. claude-project:skill-name  (项目级 Claude 技能)</span></span>\n<span class="line"><span>3. skill-name                (用户级 OpenCode 技能)</span></span>\n<span class="line"><span>4. claude-user:skill-name    (用户级 Claude 技能)</span></span>\n<span class="line"><span>5. claude-plugins:skill-name (插件市场技能)</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">命名空间引用</p><p>你可以显式指定命名空间：<code>use_skill(&quot;project:my-skill&quot;)</code><br> 或者让插件自动匹配：<code>use_skill(&quot;my-skill&quot;)</code></p></div><p><strong>第一个发现的匹配生效</strong>，后续同名技能被忽略。这允许项目级技能覆盖用户级技能。</p><h2 id="压缩恢复机制" tabindex="-1">压缩恢复机制 <a class="header-anchor" href="#压缩恢复机制" aria-label="Permalink to &quot;压缩恢复机制&quot;">​</a></h2><p>长时间会话中，OpenCode 会执行上下文压缩以节省 token。插件通过以下机制确保 Superpowers 持续可用：</p><ol><li><strong>监听事件</strong>：插件监听 <code>session.compacted</code> 事件</li><li><strong>重新注入</strong>：压缩完成后，自动重新注入 Superpowers 内容</li><li><strong>无感切换</strong>：AI 的工作流指导始终存在，不会因压缩而中断</li></ol><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>Superpowers 集成提供了严格的工作流指导，核心要点：</p><ul><li><strong>安装 Superpowers</strong>：选择 Claude Code 插件或 OpenCode 技能任一方式</li><li><strong>启用环境变量</strong>：设置 <code>OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE=true</code></li><li><strong>自动注入</strong>：插件在会话初始化和压缩后自动注入内容</li><li><strong>工具映射</strong>：自动将 Superpowers 工具名映射到 OpenCode 原生工具</li><li><strong>命名空间优先级</strong>：项目级技能优先于用户级技能</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../namespaces-and-priority/">命名空间与技能优先级</a></strong>。</p><p>你会学到：</p><ul><li>理解技能的命名空间系统和发现优先级规则</li><li>掌握如何使用命名空间明确指定技能来源</li><li>了解同名技能的覆盖和冲突处理机制</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>Superpowers 集成模块</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/superpowers.ts#L1-L59" target="_blank" rel="noreferrer"><code>src/superpowers.ts</code></a></td><td>1-59</td></tr><tr><td>工具映射定义</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/superpowers.ts#L12-L16" target="_blank" rel="noreferrer"><code>src/superpowers.ts</code></a></td><td>12-16</td></tr><tr><td>技能命名空间定义</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/superpowers.ts#L18-L25" target="_blank" rel="noreferrer"><code>src/superpowers.ts</code></a></td><td>18-25</td></tr><tr><td>Superpowers 内容注入函数</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/superpowers.ts#L31-L58" target="_blank" rel="noreferrer"><code>src/superpowers.ts</code></a></td><td>31-58</td></tr><tr><td>环境变量检查</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/superpowers.ts#L37" target="_blank" rel="noreferrer"><code>src/superpowers.ts</code></a></td><td>37</td></tr><tr><td>会话初始化注入调用</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L101" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>101</td></tr><tr><td>压缩后重新注入</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L148" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>148</td></tr></tbody></table><p><strong>关键常量</strong>：</p><ul><li><code>OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE</code>：环境变量，设置为 <code>&#39;true&#39;</code> 启用 Superpowers 模式</li></ul><p><strong>关键函数</strong>：</p><ul><li><code>maybeInjectSuperpowersBootstrap()</code>：检查环境变量和技能存在性，注入 Superpowers 内容</li><li><code>discoverAllSkills()</code>：发现所有可用技能（用于查找 <code>using-superpowers</code>）</li><li><code>injectSyntheticContent()</code>：将内容以 synthetic 消息形式注入会话</li></ul></details>',77)])])}const u=e(l,[["render",n]]);export{k as __pageData,u as default};
